import { useState, useEffect } from 'react';
import { motion, useScroll, useSpring, useMotionValue } from 'framer-motion';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import About from './components/About';
import Skills from './components/Skills';
import Projects from './components/Projects';
import InteractivePreview from './components/InteractivePreview';
import Education from './components/Education';
import StatsSection from './components/StatsSection';
import Testimonials from './components/Testimonials';
import Contact from './components/Contact';
import Footer from './components/Footer';
import GithubActivity from './components/GithubActivity';

function App() {
  const { scrollYProgress } = useScroll();
  const scaleX = useSpring(scrollYProgress, {
    stiffness: 100,
    damping: 30,
    restDelta: 0.001
  });

  // High-performance cursor tracking using Framer Motion values
  const cursorX = useMotionValue(-100);
  const cursorY = useMotionValue(-100);

  const springConfig = { damping: 25, stiffness: 400, mass: 0.2 };
  const cursorXSpring = useSpring(cursorX, springConfig);
  const cursorYSpring = useSpring(cursorY, springConfig);

  const [isHovering, setIsHovering] = useState(false);

  useEffect(() => {
    const mouseMove = (e) => {
      cursorX.set(e.clientX - 16);
      cursorY.set(e.clientY - 16);
    };

    const handleMouseOver = (e) => {
      // Check if hovering over interactive elements
      if (
        e.target.tagName.toLowerCase() === 'a' ||
        e.target.tagName.toLowerCase() === 'button' ||
        e.target.closest('a') ||
        e.target.closest('button') ||
        e.target.classList.contains('interactive-hover')
      ) {
        setIsHovering(true);
      } else {
        setIsHovering(false);
      }
    };

    window.addEventListener("mousemove", mouseMove);
    window.addEventListener("mouseover", handleMouseOver);

    return () => {
      window.removeEventListener("mousemove", mouseMove);
      window.removeEventListener("mouseover", handleMouseOver);
    };
  }, [cursorX, cursorY]);

  return (
    <div className="relative min-h-screen font-sans antialiased transition-colors duration-500">

      {/* Scroll Progress Indicator */}
      <motion.div
        className="fixed top-0 left-0 right-0 h-1 bg-gradient-to-r from-primary via-accent to-secondary origin-left z-[100]"
        style={{ scaleX }}
      />

      {/* Premium Custom Cursor (Hidden on mobile) */}
      <motion.div
        style={{
          x: cursorXSpring,
          y: cursorYSpring,
        }}
        animate={{
          scale: isHovering ? 2.5 : 1,
          opacity: isHovering ? 0.3 : 0.6,
          backgroundColor: isHovering ? "#0ea5e9" : "transparent"
        }}
        transition={{ type: "tween", ease: "backOut", duration: 0.15 }}
        className="fixed top-0 left-0 w-8 h-8 rounded-full border border-primary dark:border-sky-400 pointer-events-none z-[999] hidden md:block backdrop-invert mix-blend-difference"
      />

      {/* Subtle Grain/Noise Overlay for depth */}
      <div className="noise-overlay"></div>

      {/* Abstract Background Elements (Mesh Gradients) */}
      <div className="fixed inset-0 z-0 overflow-hidden pointer-events-none">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] rounded-full bg-primary/10 dark:bg-primary/5 mix-blend-multiply dark:mix-blend-screen filter blur-[120px] animate-blob"></div>
        <div className="absolute top-[20%] right-[-10%] w-[35%] h-[35%] rounded-full bg-secondary/10 dark:bg-secondary/5 mix-blend-multiply dark:mix-blend-screen filter blur-[120px] animate-blob animation-delay-2000"></div>
        <div className="absolute bottom-[-10%] left-[20%] w-[40%] h-[40%] rounded-full bg-cyan-500/10 dark:bg-cyan-500/5 mix-blend-multiply dark:mix-blend-screen filter blur-[120px] animate-blob animation-delay-4000"></div>
      </div>

      {/* Main Content */}
      <div className="relative z-10 w-full">
        <Navbar />
        <main className="w-full">
          <Hero />
          <About />
          <Skills />
          <Projects />
          <GithubActivity />
          {/* <InteractivePreview /> */}
          <Education />
          <StatsSection />
          <Testimonials />
          <Contact />
        </main>
        <Footer />
      </div>
    </div>
  );
}

export default App;

import { motion } from 'framer-motion';
import { Target, Zap, ShieldCheck } from 'lucide-react';

const About = () => {
    return (
        <section id="about" className="py-24 relative overflow-hidden bg-white/50 dark:bg-slate-900/50 transition-colors duration-500">
            <div className="w-11/12 max-w-7xl mx-auto px-4 sm:px-6 relative z-10">

                {/* Header */}
                <motion.div
                    initial={{ opacity: 0, y: 30 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true, margin: "-100px" }}
                    className="text-center mb-20"
                >
                    <span className="inline-block py-1.5 px-4 rounded-full bg-secondary/10 dark:bg-secondary/20 text-secondary dark:text-purple-300 font-bold text-sm mb-4 tracking-wider uppercase border border-secondary/20">The Narrative</span>
                    <h2 className="text-4xl md:text-5xl font-extrabold text-slate-900 dark:text-white mb-6 font-heading tracking-tight">
                        Why <span className="text-gradient">Hire Me?</span>
                    </h2>
                    <div className="w-24 h-1 bg-gradient-to-r from-primary to-secondary mx-auto rounded-full mb-6 relative overflow-hidden">
                        <motion.div
                            initial={{ x: "-100%" }}
                            whileInView={{ x: "100%" }}
                            transition={{ repeat: Infinity, duration: 2, ease: "linear" }}
                            className="absolute inset-0 bg-white/50 w-full h-full skew-x-12"
                        ></motion.div>
                    </div>

                    <motion.div
                        initial="hidden"
                        whileInView="visible"
                        viewport={{ once: true }}
                        variants={{
                            hidden: { opacity: 0 },
                            visible: {
                                opacity: 1,
                                transition: { staggerChildren: 0.05 }
                            }
                        }}
                        className="max-w-3xl mx-auto text-lg md:text-xl font-medium leading-relaxed flex flex-wrap justify-center gap-x-1.5"
                    >
                        {"I don't just write code; I solve business problems. My philosophy is rooted in building digital products that are as performant as they are beautiful.".split(" ").map((word, idx) => (
                            <motion.span
                                key={idx}
                                variants={{
                                    hidden: { y: 20, opacity: 0 },
                                    visible: { y: 0, opacity: 1 }
                                }}
                                className="text-slate-600 dark:text-slate-400"
                            >
                                {word}
                            </motion.span>
                        ))}
                    </motion.div>
                </motion.div>

                <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 lg:gap-8 items-start">

                    {/* The Story Section */}
                    <motion.div
                        initial={{ opacity: 0, x: -40 }}
                        whileInView={{ opacity: 1, x: 0 }}
                        viewport={{ once: true, margin: "-100px" }}
                        className="lg:col-span-5 space-y-8"
                    >
                        <div className="glass-premium p-8 md:p-10 rounded-3xl relative overflow-hidden interactive-hover">
                            {/* Decorative background glow */}
                            <div className="absolute top-0 right-0 w-64 h-64 bg-primary/10 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2"></div>

                            <h3 className="text-3xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-slate-900 via-slate-700 to-slate-900 dark:from-white dark:via-slate-300 dark:to-white font-heading mb-6">The Journey</h3>
                            <div className="space-y-6 text-slate-600 dark:text-slate-400 font-medium leading-relaxed">
                                <p>
                                    My frontend journey started with a deep curiosity for how users interact with digital spaces. I realized early on that incredible design loses its impact if the engineering behind it is slow or inaccessible.
                                </p>
                                <p>
                                    Today, my focus is laser-sharp: <strong className="text-slate-900 dark:text-slate-200">React ecosystems, micro-interactions, and enterprise-grade performance.</strong> I love transforming complex data systems into intuitive, accessible dashboards and captivating landing pages.
                                </p>
                                <p>
                                    When I'm not optimizing component renders, I'm analyzing top-tier SaaS interfaces or contributing to modern UI design systems.
                                </p>
                            </div>
                        </div>
                    </motion.div>

                    {/* The Value Props */}
                    <motion.div
                        initial={{ opacity: 0, x: 40 }}
                        whileInView={{ opacity: 1, x: 0 }}
                        viewport={{ once: true, margin: "-100px" }}
                        className="lg:col-span-7 grid grid-cols-1 md:grid-cols-2 gap-6"
                    >
                        {[
                            {
                                icon: Target,
                                color: "text-emerald-500",
                                bg: "bg-emerald-500/10",
                                border: "border-emerald-500/20",
                                title: "Pixel-Perfect Engineering",
                                desc: "Design handoffs aren't just suggestions. I map Figma coordinates to responsive CSS with ruthless precision and zero visual regressions."
                            },
                            {
                                icon: Zap,
                                color: "text-amber-500",
                                bg: "bg-amber-500/10",
                                border: "border-amber-500/20",
                                title: "Performance First",
                                desc: "I prioritize 90+ Lighthouse scores. Core Web Vitals, lazy-loading, and bundle optimization are baked into my workflow from day one."
                            },
                            {
                                icon: ShieldCheck,
                                color: "text-blue-500",
                                bg: "bg-blue-500/10",
                                border: "border-blue-500/20",
                                title: "Scalable Architectures",
                                desc: "Clean abstractions, highly reusable components, and strict TypeScript/React patterns ensure codebases survive long after v1."
                            }
                        ].map((item, idx) => (
                            <motion.div
                                key={idx}
                                whileHover={{ y: -5 }}
                                className={`glass-premium p-8 rounded-[2rem] hover:border-slate-300 dark:hover:border-slate-600 transition-all duration-300 interactive-hover ${idx === 2 ? 'md:col-span-2' : ''}`}
                            >
                                <div className={`w-14 h-14 rounded-2xl flex items-center justify-center mb-6 ${item.bg} ${item.color}`}>
                                    <item.icon size={26} />
                                </div>
                                <h4 className="text-xl font-bold text-slate-900 dark:text-white mb-3 font-heading">{item.title}</h4>
                                <p className="text-slate-600 dark:text-slate-400 font-medium leading-relaxed">
                                    {item.desc}
                                </p>
                            </motion.div>
                        ))}
                    </motion.div>
                </div>
            </div>
        </section>
    );
};

export default About;

import { motion } from 'framer-motion';
import { Mail, Phone, MapPin, Send } from 'lucide-react';
import { portfolioData } from '../data';
import { useRef, useState } from 'react';

// Custom Magnetic effect wrapper
const MagneticWrapper = ({ children, className }) => {
    const ref = useRef(null);
    const [position, setPosition] = useState({ x: 0, y: 0 });

    const handleMouse = (e) => {
        const { clientX, clientY } = e;
        const { height, width, left, top } = ref.current.getBoundingClientRect();
        const middleX = clientX - (left + width / 2);
        const middleY = clientY - (top + height / 2);
        setPosition({ x: middleX * 0.2, y: middleY * 0.2 });
    };

    const reset = () => {
        setPosition({ x: 0, y: 0 });
    };

    const { x, y } = position;
    return (
        <motion.div
            style={{ position: 'relative' }}
            ref={ref}
            onMouseMove={handleMouse}
            onMouseLeave={reset}
            animate={{ x, y }}
            transition={{ type: "spring", stiffness: 150, damping: 15, mass: 0.1 }}
            className={className}
        >
            {children}
        </motion.div>
    );
};

const Contact = () => {
    const { email, phone, location } = portfolioData.personalInfo;

    return (
        <section id="contact" className="py-24 relative overflow-hidden bg-slate-50/50 dark:bg-slate-900/50 transition-colors duration-500">
            {/* Background Orbs */}
            <div className="absolute top-1/4 left-1/4 w-[400px] h-[400px] bg-primary/5 dark:bg-primary/10 blur-[100px] rounded-full pointer-events-none"></div>
            <div className="absolute bottom-1/4 right-1/4 w-[400px] h-[400px] bg-secondary/5 dark:bg-secondary/10 blur-[100px] rounded-full pointer-events-none"></div>

            <div className="w-11/12 max-w-7xl mx-auto px-4 sm:px-6 relative z-10">
                <motion.div
                    initial={{ opacity: 0, y: 30 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true, margin: "-100px" }}
                    className="text-center mb-20"
                >
                    <span className="inline-block py-1.5 px-4 rounded-full bg-primary/10 dark:bg-primary/20 text-primary dark:text-sky-300 font-bold text-sm mb-4 tracking-wider uppercase border border-primary/20">Connect</span>
                    <h2 className="text-4xl md:text-5xl font-extrabold text-slate-900 dark:text-white mb-6 font-heading">
                        Get In <span className="text-gradient">Touch</span>
                    </h2>
                    <div className="w-24 h-1 bg-gradient-to-r from-primary to-secondary mx-auto rounded-full mb-6"></div>
                    <p className="text-slate-600 dark:text-slate-400 max-w-2xl mx-auto text-lg font-medium">
                        Have a project in mind or just want to say hi? Feel free to connect!
                    </p>
                </motion.div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-16 lg:gap-24">
                    {/* Contact Information */}
                    <motion.div
                        initial={{ opacity: 0, x: -40 }}
                        whileInView={{ opacity: 1, x: 0 }}
                        viewport={{ once: true, margin: "-100px" }}
                        className="space-y-10"
                    >
                        <div>
                            <h3 className="text-3xl font-extrabold text-slate-900 dark:text-white mb-4 tracking-tight font-heading">Let's build something awesome together!</h3>
                            <p className="text-slate-600 dark:text-slate-400 text-lg leading-relaxed font-medium">
                                I am currently open to new opportunities. Whether you have a question or just want to say hi, I'll try my best to get back to you!
                            </p>
                        </div>

                        <div className="space-y-8">
                            {[
                                { icon: Mail, label: 'Email Me', value: email, link: `mailto:${email}`, color: 'text-primary', bgHover: 'group-hover:bg-primary' },
                                { icon: Phone, label: 'Call Me', value: phone, link: `tel:${phone}`, color: 'text-secondary', bgHover: 'group-hover:bg-secondary' },
                                { icon: MapPin, label: 'Location', value: location, link: null, color: 'text-emerald-500', bgHover: 'group-hover:bg-emerald-500' }
                            ].map((info, index) => (
                                <MagneticWrapper key={index} className="flex items-center gap-6 group cursor-pointer w-max">
                                    <div className={`w-14 h-14 bg-white dark:bg-slate-800/80 backdrop-blur-md rounded-2xl flex items-center justify-center ${info.color} shadow-[0_5px_15px_rgba(0,0,0,0.05)] dark:shadow-[0_5px_15px_rgba(0,0,0,0.2)] border border-slate-100 dark:border-slate-700/50 ${info.bgHover} group-hover:text-white group-hover:-translate-y-1 group-hover:scale-105 transition-all duration-300 pointer-events-none`}>
                                        <info.icon size={24} />
                                    </div>
                                    <div>
                                        <p className="text-sm text-slate-500 dark:text-slate-400 font-bold tracking-wide uppercase mb-1 pointer-events-none">{info.label}</p>
                                        {info.link ? (
                                            <a href={info.link} className="text-xl font-bold text-slate-900 dark:text-white hover:text-primary dark:hover:text-primary transition-colors inline-block pointer-events-auto">
                                                {info.value}
                                            </a>
                                        ) : (
                                            <p className="text-xl font-bold text-slate-900 dark:text-white pointer-events-none">{info.value}</p>
                                        )}
                                    </div>
                                </MagneticWrapper>
                            ))}
                        </div>
                    </motion.div>

                    {/* Contact Form */}
                    <motion.div
                        initial={{ opacity: 0, x: 40 }}
                        whileInView={{ opacity: 1, x: 0 }}
                        viewport={{ once: true, margin: "-100px" }}
                        className="bg-white/80 dark:bg-slate-800/40 backdrop-blur-xl p-8 sm:p-10 rounded-[2rem] border border-slate-200 dark:border-slate-700/50 shadow-xl relative overflow-hidden"
                    >
                        {/* Shimmer effect line */}
                        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-primary via-secondary to-primary opacity-50 bg-[length:200%_auto] animate-[shimmer_3s_linear_infinite]"></div>

                        <form className="space-y-6" onSubmit={(e) => e.preventDefault()}>
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                                <div className="group">
                                    <label htmlFor="name" className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2 group-focus-within:text-primary transition-colors">Your Name</label>
                                    <input
                                        type="text"
                                        id="name"
                                        className="w-full bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700/50 rounded-xl px-5 py-4 text-slate-900 dark:text-white placeholder-slate-400 dark:placeholder-slate-500 focus:outline-none focus:border-primary focus:ring-2 focus:ring-primary/20 transition-all shadow-inner"
                                        placeholder="John Doe"
                                    />
                                </div>
                                <div className="group">
                                    <label htmlFor="email" className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2 group-focus-within:text-primary transition-colors">Your Email</label>
                                    <input
                                        type="email"
                                        id="email"
                                        className="w-full bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700/50 rounded-xl px-5 py-4 text-slate-900 dark:text-white placeholder-slate-400 dark:placeholder-slate-500 focus:outline-none focus:border-primary focus:ring-2 focus:ring-primary/20 transition-all shadow-inner"
                                        placeholder="john@example.com"
                                    />
                                </div>
                            </div>
                            <div className="group">
                                <label htmlFor="subject" className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2 group-focus-within:text-primary transition-colors">Subject</label>
                                <input
                                    type="text"
                                    id="subject"
                                    className="w-full bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700/50 rounded-xl px-5 py-4 text-slate-900 dark:text-white placeholder-slate-400 dark:placeholder-slate-500 focus:outline-none focus:border-primary focus:ring-2 focus:ring-primary/20 transition-all shadow-inner"
                                    placeholder="Project Inquiry"
                                />
                            </div>
                            <div className="group">
                                <label htmlFor="message" className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2 group-focus-within:text-primary transition-colors">Message</label>
                                <textarea
                                    id="message"
                                    rows="5"
                                    className="w-full bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700/50 rounded-xl px-5 py-4 text-slate-900 dark:text-white placeholder-slate-400 dark:placeholder-slate-500 focus:outline-none focus:border-primary focus:ring-2 focus:ring-primary/20 transition-all resize-none shadow-inner"
                                    placeholder="Hello, I'd like to talk about..."
                                ></textarea>
                            </div>

                            <MagneticWrapper>
                                <motion.button
                                    whileTap={{ scale: 0.95 }}
                                    type="submit"
                                    className="w-full py-4 bg-gradient-to-r from-primary to-sky-500 text-white rounded-xl font-bold flex items-center justify-center gap-3 hover:shadow-[0_10px_30px_rgba(14,165,233,0.3)] transition-all duration-300 hover:scale-[1.02] interactive-hover"
                                >
                                    <span>Send Message</span>
                                    <Send size={20} className="animate-pulse" />
                                </motion.button>
                            </MagneticWrapper>
                            <p className="text-center text-xs text-slate-500 dark:text-slate-400 mt-4 font-medium flex items-center justify-center gap-2">
                                <span className="w-2 h-2 rounded-full bg-emerald-500 animate-[blob_2s_infinite]"></span>
                                Typically replies within 24 hours
                            </p>
                        </form>
                    </motion.div>
                </div>
            </div>
        </section>
    );
};

export default Contact;

import { motion } from 'framer-motion';
import { portfolioData } from '../data';
import { GraduationCap, Award, Calendar, MapPin } from 'lucide-react';

const Education = () => {
    const { education, certifications } = portfolioData;

    return (
        <section id="education" className="py-24 relative overflow-hidden bg-white dark:bg-transparent transition-colors duration-500">
            {/* Decorative Orbs */}
            <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-primary/5 dark:bg-primary/10 rounded-full blur-[100px] pointer-events-none translate-x-1/2 -translate-y-1/2"></div>
            <div className="absolute bottom-0 left-0 w-[500px] h-[500px] bg-secondary/5 dark:bg-secondary/10 rounded-full blur-[100px] pointer-events-none -translate-x-1/2 translate-y-1/2"></div>

            <div className="w-11/12 max-w-7xl mx-auto px-4 sm:px-6 relative z-10">
                <motion.div
                    initial={{ opacity: 0, y: 30 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true, margin: "-100px" }}
                    className="text-center mb-20"
                >
                    <span className="inline-block py-1.5 px-4 rounded-full bg-primary/10 dark:bg-primary/20 text-primary dark:text-sky-300 font-bold text-sm mb-4 tracking-wider uppercase border border-primary/20">Journey</span>
                    <h2 className="text-4xl md:text-5xl font-extrabold text-slate-900 dark:text-white mb-6 font-heading">
                        Education & <span className="text-gradient">Certifications</span>
                    </h2>
                    <div className="w-24 h-1 bg-gradient-to-r from-primary to-secondary mx-auto rounded-full mb-6"></div>
                    <p className="text-slate-600 dark:text-slate-400 max-w-2xl mx-auto text-lg font-medium">
                        My academic background and professional training that shaped my development journey.
                    </p>
                </motion.div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-16 lg:gap-24">
                    {/* Education Timeline */}
                    <div>
                        <div className="flex items-center gap-5 mb-12">
                            <div className="w-16 h-16 rounded-2xl bg-blue-100 dark:bg-blue-500/10 flex items-center justify-center text-blue-600 dark:text-primary border border-blue-200 dark:border-blue-500/20 shadow-[0_5px_15px_rgba(14,165,233,0.15)]">
                                <GraduationCap size={32} />
                            </div>
                            <h3 className="text-3xl font-bold text-slate-900 dark:text-white font-heading">Education</h3>
                        </div>

                        <div className="relative border-l-2 border-slate-200 dark:border-slate-700/80 pl-8 ml-8 space-y-12">
                            {education.map((edu, index) => (
                                <motion.div
                                    key={index}
                                    initial={{ opacity: 0, x: -30 }}
                                    whileInView={{ opacity: 1, x: 0 }}
                                    viewport={{ once: true, margin: "-50px" }}
                                    transition={{ duration: 0.5, delay: index * 0.1 }}
                                    className="relative group"
                                >
                                    {/* Timeline Dot */}
                                    <div className="absolute -left-[41px] top-2 w-5 h-5 rounded-full bg-white dark:bg-darker border-4 border-primary group-hover:scale-150 group-hover:bg-primary transition-all duration-300 shadow-[0_0_10px_rgba(14,165,233,0.5)]"></div>

                                    <div className="bg-slate-50 dark:bg-slate-800/40 border border-slate-200 dark:border-slate-700/50 p-8 rounded-2xl group-hover:-translate-y-2 hover:border-primary/40 dark:hover:border-primary/50 transition-all duration-300 shadow-lg hover:shadow-[0_10px_30px_rgba(14,165,233,0.1)] relative overflow-hidden backdrop-blur-sm">
                                        <div className="absolute top-0 right-0 w-32 h-32 bg-primary/5 dark:bg-primary/10 rounded-full blur-[40px] group-hover:bg-primary/10 dark:group-hover:bg-primary/20 transition-colors"></div>

                                        <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-primary/10 dark:bg-primary/20 text-primary dark:text-sky-300 text-sm font-bold mb-4 border border-primary/20">
                                            <Calendar size={14} />
                                            <span>{edu.duration}</span>
                                        </div>

