import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import GitHubCalendar from 'react-github-calendar';
import { GitCommit, Star } from 'lucide-react';

const GithubActivity = () => {
    const [theme, setTheme] = useState('dark');

    useEffect(() => {
        const observer = new MutationObserver((mutations) => {
            mutations.forEach((mutation) => {
                if (mutation.attributeName === 'class') {
                    setTheme(document.documentElement.classList.contains('dark') ? 'dark' : 'light');
                }
            });
        });

        observer.observe(document.documentElement, { attributes: true });
        setTheme(document.documentElement.classList.contains('dark') ? 'dark' : 'light');

        return () => observer.disconnect();
    }, []);

    const calendarTheme = {
        light: ['#f0fdfa', '#ccfbf1', '#5eead4', '#14b8a6', '#0f766e'],
        dark: ['#1e293b', '#0f766e', '#14b8a6', '#5eead4', '#ccfbf1']
    };

    return (
        <section className="py-24 relative overflow-hidden bg-slate-50/50 dark:bg-transparent transition-colors duration-500">
            <div className="absolute top-0 right-1/4 w-[300px] h-[300px] bg-emerald-500/5 dark:bg-emerald-500/10 blur-[120px] rounded-full pointer-events-none"></div>

            <div className="w-11/12 max-w-7xl mx-auto px-4 sm:px-6 relative z-10">
                <motion.div
                    initial={{ opacity: 0, y: 30 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true, margin: "-100px" }}
                    className="text-center mb-16"
                >
                    <span className="inline-block py-1.5 px-4 rounded-full bg-emerald-500/10 dark:bg-emerald-500/20 text-emerald-600 dark:text-emerald-300 font-bold text-sm mb-4 tracking-wider uppercase border border-emerald-500/20">Open Source</span>
                    <h2 className="text-4xl md:text-5xl font-extrabold text-slate-900 dark:text-white mb-6 font-heading tracking-tight">
                        My <span className="text-transparent bg-clip-text bg-gradient-to-r from-emerald-400 to-cyan-500">Contributions</span>
                    </h2>
                    <div className="w-24 h-1 bg-gradient-to-r from-emerald-400 to-cyan-500 mx-auto rounded-full mb-6 relative overflow-hidden">
                    </div>
                    <p className="text-slate-600 dark:text-slate-400 max-w-2xl mx-auto text-lg font-medium">
                        Consistency is key. Here's a snapshot of my daily code commits and open source activity.
                    </p>
                </motion.div>

                <motion.div
                    initial={{ opacity: 0, scale: 0.95 }}
                    whileInView={{ opacity: 1, scale: 1 }}
                    viewport={{ once: true, margin: "-100px" }}
                    transition={{ type: "spring", stiffness: 100, damping: 20 }}
                    className="glass-premium p-8 sm:p-12 rounded-[2.5rem] relative overflow-hidden shadow-2xl flex flex-col items-center justify-center max-w-5xl mx-auto interactive-hover"
                >
                    <div className="flex items-center gap-3 mb-8 w-full justify-start border-b border-slate-200 dark:border-slate-700/50 pb-6">
                        <div className="p-3 bg-emerald-500/10 dark:bg-emerald-500/20 rounded-xl text-emerald-600 dark:text-emerald-400 border border-emerald-500/20">
                            <GitCommit size={24} />
                        </div>
                        <div>
                            <h3 className="text-2xl font-bold text-slate-900 dark:text-white font-heading">GitHub Activity</h3>
                            <p className="text-slate-500 dark:text-slate-400 text-sm font-medium">@Firoz671</p>
                        </div>
                    </div>

                    <div className="w-full overflow-x-auto pb-4 custom-scrollbar flex justify-center">
                        <div className="min-w-max p-4 bg-white/50 dark:bg-slate-900/40 rounded-2xl border border-slate-200/50 dark:border-white/5">
                            <GitHubCalendar
                                username="Firoz671"
                                blockSize={14}
                                blockMargin={6}
                                colorScheme={theme}
                                theme={calendarTheme}
                                fontSize={14}
                            />
