import { useState, useEffect } from 'react';
import { motion, useMotionValue, useTransform, useSpring } from 'framer-motion';
import { useGitHubRepos } from '../hooks/useGitHubRepos';
import { ExternalLink, Star, GitFork, ArrowRight } from 'lucide-react';
import { FaGithub } from 'react-icons/fa';
import ProjectModal from './ProjectModal';

const ProjectCard = ({ repo, getLanguageColor, variants, onClick }) => {
    const x = useMotionValue(0);
    const y = useMotionValue(0);

    const mouseXSpring = useSpring(x, { stiffness: 400, damping: 25 });
    const mouseYSpring = useSpring(y, { stiffness: 400, damping: 25 });

    const rotateX = useTransform(mouseYSpring, [-0.5, 0.5], ["12deg", "-12deg"]);
    const rotateY = useTransform(mouseXSpring, [-0.5, 0.5], ["-12deg", "12deg"]);

    const handleMouseMove = (e) => {
        const rect = e.currentTarget.getBoundingClientRect();
        const width = rect.width;
        const height = rect.height;
        const mouseX = e.clientX - rect.left;
        const mouseY = e.clientY - rect.top;
        x.set(mouseX / width - 0.5);
        y.set(mouseY / height - 0.5);
    };

    const handleMouseLeave = () => {
        x.set(0);
        y.set(0);
    };

    return (
        <motion.div variants={variants} className="relative z-10 cursor-pointer interactive-hover" style={{ perspective: 1200 }} onClick={() => onClick(repo)}>
            <motion.div
                style={{ rotateX, rotateY, transformStyle: "preserve-3d" }}
                onMouseMove={handleMouseMove}
                onMouseLeave={handleMouseLeave}
                className="bg-white/80 dark:bg-slate-800/40 backdrop-blur-2xl rounded-[2rem] p-8 flex flex-col justify-between group h-[380px] border border-slate-200 dark:border-white/10 transition-colors duration-500 shadow-lg hover:shadow-[0_30px_60px_rgba(14,165,233,0.2)] relative"
            >
                {/* Animated Border Glow Pattern */}
                <div className="absolute -inset-[1px] bg-gradient-to-r from-primary via-secondary to-primary rounded-[2rem] opacity-0 group-hover:opacity-100 transition-opacity duration-500 bg-[length:200%_auto] animate-[shimmer_3s_linear_infinite] z-[-1] blur-[8px]"></div>
                <div className="absolute -inset-[1px] bg-gradient-to-r from-primary via-secondary to-primary rounded-[2rem] opacity-0 group-hover:opacity-100 transition-opacity duration-500 bg-[length:200%_auto] animate-[shimmer_3s_linear_infinite] z-[-1]"></div>

                {/* Background base to cover the glow */}
                <div className="absolute inset-0 bg-white/90 dark:bg-slate-900/90 rounded-[calc(2rem-1px)] z-[-1] backdrop-blur-3xl"></div>

                {/* Hover gradient effect interior */}
                <div className="absolute -top-20 -right-20 w-40 h-40 bg-primary/10 dark:bg-primary/20 blur-[50px] rounded-full group-hover:scale-[2] transition-transform duration-700 ease-out pointer-events-none"></div>
                <div className="absolute -bottom-20 -left-20 w-40 h-40 bg-secondary/10 dark:bg-secondary/20 blur-[50px] rounded-full group-hover:scale-[2] transition-transform duration-700 ease-out pointer-events-none"></div>

                <div className="relative z-10 flex flex-col h-full w-full pointer-events-none" style={{ transform: "translateZ(50px)" }}>
                    <div className="flex justify-between items-start mb-6">
                        <div className="w-14 h-14 rounded-2xl bg-white dark:bg-slate-800/80 flex items-center justify-center text-slate-800 dark:text-white shadow-[0_5px_15px_rgba(0,0,0,0.05)] dark:shadow-[0_5px_15px_rgba(0,0,0,0.3)] group-hover:-translate-y-1 group-hover:shadow-[0_15px_30px_rgba(14,165,233,0.3)] transition-all duration-300 border border-slate-100 dark:border-slate-700/50">
                            <FaGithub size={28} />
                        </div>
                        <div className="flex bg-slate-100 dark:bg-slate-800/80 items-center justify-center w-10 h-10 rounded-full opacity-0 group-hover:opacity-100 translate-y-2 group-hover:translate-y-0 shadow-lg transition-all duration-300 text-primary dark:text-sky-400">
                            <ArrowRight size={18} className="-rotate-45" />
                        </div>
                    </div>

                    <div className="flex-1 w-full mt-2">
                        <h3 className="text-2xl font-extrabold text-slate-900 dark:text-white group-hover:text-primary dark:group-hover:text-primary transition-colors tracking-wide mb-3 line-clamp-1 font-heading">
                            {repo.name.replace(/-/g, ' ')}
                        </h3>
                        <p className="text-slate-600 dark:text-slate-400 text-sm leading-relaxed line-clamp-3 group-hover:text-slate-700 dark:group-hover:text-slate-300 transition-colors font-medium">
                            {repo.description || 'A fascinating project waiting to be explored. Dive into the code to see more!'}
                        </p>
                    </div>

                    <div className="pt-6 mt-4 border-t border-slate-200 dark:border-slate-700/50 flex items-center justify-between w-full">
                        <div className="flex items-center">
                            {repo.language ? (
                                <span className={`text-[11px] uppercase tracking-wider font-bold px-3 py-1.5 rounded-full border ${getLanguageColor(repo.language)} transition-colors backdrop-blur-md`}>
                                    {repo.language}
                                </span>
                            ) : (
                                <span className="text-xs text-slate-500 italic px-3 py-1">No language</span>
                            )}
                        </div>

                        <div className="flex gap-4 text-slate-500 dark:text-slate-400 text-sm font-bold">
                            <div className="flex items-center gap-1.5 hover:text-yellow-500 dark:hover:text-yellow-400 transition-colors" title="Stars">
                                <Star size={16} className="group-hover:fill-yellow-500/20 group-hover:text-yellow-500 dark:group-hover:text-yellow-400 transition-colors" />
                                <span className="group-hover:text-yellow-500 dark:group-hover:text-yellow-400 transition-colors">{repo.stargazers_count}</span>
                            </div>
                            <div className="flex items-center gap-1.5 hover:text-emerald-500 dark:hover:text-emerald-400 transition-colors" title="Forks">
                                <GitFork size={16} className="group-hover:text-emerald-500 dark:group-hover:text-emerald-400 transition-colors" />
                                <span className="group-hover:text-emerald-500 dark:group-hover:text-emerald-400 transition-colors">{repo.forks_count}</span>
                            </div>
                        </div>
                    </div>
                </div>
            </motion.div>
        </motion.div>
    );
};

const Projects = () => {
