            CSS: "bg-[#1572B6]/10 text-blue-600 dark:text-[#1572B6] border-[#1572B6]/30",
            TypeScript: "bg-[#3178C6]/10 text-blue-700 dark:text-[#3178C6] border-[#3178C6]/30",
