                        <span className="block text-4xl mb-3">ÔÜá´©Å</span>
                        <p className="font-bold text-lg">Failed to load projects</p>
                        <p className="text-sm mt-1 opacity-80">{error}</p>
                    </div>
                )}

                <motion.div
                    variants={containerVariants}
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true, margin: "-50px" }}
