                                        <div className="h-4 bg-slate-200 dark:bg-slate-700/80 rounded block w-full animate-pulse"></div>
                                        <div className="h-4 bg-slate-200 dark:bg-slate-700/80 rounded block w-full animate-pulse"></div>
                                        <div className="h-4 bg-slate-200 dark:bg-slate-700/80 rounded block w-2/3 animate-pulse"></div>
