                >
                    <a href="https://github.com/Firoz671" target="_blank" rel="noreferrer" className="group relative inline-flex items-center gap-3 px-8 py-4 bg-slate-900 dark:bg-slate-800 text-white rounded-full font-bold hover:bg-slate-800 dark:hover:bg-slate-700 transition-all shadow-[0_5px_20px_rgba(0,0,0,0.1)] hover:shadow-[0_15px_30px_rgba(14,165,233,0.3)] hover:-translate-y-1 overflow-hidden border border-slate-700 interactive-hover">
                        <span className="absolute inset-0 w-full h-full bg-gradient-to-r from-primary/20 to-secondary/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300 ease-out"></span>
                        <FaGithub size={22} className="relative z-10 group-hover:rotate-12 transition-transform duration-300" />
                        <span className="relative z-10">Discover More on GitHub</span>
                    </a>
                </motion.div>
            </div>
        </section>
    );
